import React, { useState, useEffect, useContext, useMemo, useRef, useCallback } from 'react';
import { useSpring } from '@react-spring/web';
import { useGesture } from '@use-gesture/react';
import { useMediaQuery } from 'react-responsive';

/** Moins raide que `config.stiff` pour limiter le scintillement sur la rotation. */
const flipConfig = { tension: 220, friction: 32, clamp: true };

export type Lang = 'fr' | 'en';

export interface LangContextValue {
  flick: boolean;
  setFlick: React.Dispatch<React.SetStateAction<boolean>>;
  flickValue: number;
  toggle: boolean;
  setToggle: React.Dispatch<React.SetStateAction<boolean>>;
  lang: Lang;
}

export const LangCtxt = React.createContext<LangContextValue | null>(null);

/** Cumul vertical (px) pour déclencher le changement de langue — au-delà, on “commit”. */
const WHEEL_FLIP_ACCUM = 72;
/** Degrés max pour l’aperçu avant bascule (évite des rotations absurdes). */
const WHEEL_FLICK_CAP = 220;
/** Comme l’ancien coef ~5 : degrés ≈ cumul * coef. */
const WHEEL_COEF = 4.8;
/** Après la fin de la molette, on remet le cumul à zéro. */
const WHEEL_IDLE_RESET_MS = 320;
const DRAG_TOGGLE_AT_DESKTOP = 250;
const DRAG_TOGGLE_AT_MOBILE = 120;
const DRAG_FLICK_MIN = 40;
const AXIS_RATIO = 1.15;

export function useCreateToggleScroll(
  setToggleContact: React.Dispatch<React.SetStateAction<boolean>>,
  toggleContact: boolean,
  setToggleExps: React.Dispatch<React.SetStateAction<boolean>>,
  toggleExps: boolean
) {
  const isNarrow = useMediaQuery({ maxWidth: 750 });
  const dragToggleAt = isNarrow ? DRAG_TOGGLE_AT_MOBILE : DRAG_TOGGLE_AT_DESKTOP;
  const handleMenu = useCallback(
    (limit: number, deltaX: number, direction: number) => {
      if (Math.abs(deltaX) <= limit) return;
      if (direction < 0) {
        if (!toggleContact && !toggleExps) {
          setToggleContact(true);
        } else if (!toggleContact && toggleExps) {
          setToggleExps(false);
        }
      } else if (direction > 0) {
        if (!toggleContact && !toggleExps) {
          setToggleExps(true);
        } else if (toggleContact && !toggleExps) {
          setToggleContact(false);
        }
      }
    },
    [setToggleContact, setToggleExps, toggleContact, toggleExps]
  );

  const [flick, setFlick] = useState(false);
  const [flickValue, setFlickValue] = useState(0);
  const [toggle, setToggle] = useState(false);
  const [lang, setLang] = useState<Lang>('fr');

  const wheelAcc = useRef(0);
  const wheelRaf = useRef<number | null>(null);
  const wheelIdleTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const pumpWheel = useCallback(() => {
    wheelRaf.current = null;
    const acc = wheelAcc.current;
    const abs = Math.abs(acc);
    if (abs < 0.5) return;

    if (abs >= WHEEL_FLIP_ACCUM) {
      setFlick(false);
      setToggle(prev => (prev ? prev : true));
      wheelAcc.current = 0;
      return;
    }

    const deg = Math.min(abs * WHEEL_COEF, WHEEL_FLICK_CAP);
    setFlickValue(deg);
    setFlick(true);
  }, []);

  const scheduleWheelPump = useCallback(() => {
    if (wheelRaf.current != null) return;
    wheelRaf.current = requestAnimationFrame(pumpWheel);
  }, [pumpWheel]);

  const handleGestureWheel = useCallback(
    (e: { delta: [number, number]; axis: 'x' | 'y' | undefined }) => {
      const { delta, axis } = e;
      if (axis === 'x') return;

      wheelAcc.current += delta[1];
      scheduleWheelPump();

      if (wheelIdleTimer.current) clearTimeout(wheelIdleTimer.current);
      wheelIdleTimer.current = setTimeout(() => {
        wheelAcc.current = 0;
        wheelIdleTimer.current = null;
      }, WHEEL_IDLE_RESET_MS);
    },
    [scheduleWheelPump]
  );

  /**
   * Glisser : décision au relâchement (last) pour éviter de mettre à jour le spring à chaque frame.
   * Axe vertical vs horizontal par comparaison des mouvements (plus fiable que `axis` seul au touch).
   */
  const handleGestureDrag = useCallback(
    (e: {
      event?: UIEvent;
      movement: [number, number];
      direction: [number, number];
      last: boolean;
    }) => {
      if (e.event && 'preventDefault' in e.event) {
        e.event.preventDefault();
      }

      const { movement, direction, last } = e;
      const absX = Math.abs(movement[0]);
      const absY = Math.abs(movement[1]);

      const verticalDominant = absY > absX * AXIS_RATIO;
      const horizontalDominant = absX > absY * AXIS_RATIO;

      if (!last) return;

      if (verticalDominant) {
        const distY = absY;
        if (distY >= dragToggleAt) {
          setFlick(false);
          setToggle(prev => (prev ? prev : true));
        } else if (distY > DRAG_FLICK_MIN) {
          setFlickValue(distY * 0.5);
          setFlick(true);
        }
        return;
      }

      if (horizontalDominant) {
        handleMenu(140, absX, direction[0]);
      }
    },
    [handleMenu, dragToggleAt]
  );

  useEffect(() => {
    return () => {
      if (wheelIdleTimer.current) clearTimeout(wheelIdleTimer.current);
      if (wheelRaf.current != null) cancelAnimationFrame(wheelRaf.current);
    };
  }, []);

  const bindGesture = useGesture(
    {
      onDrag: state => handleGestureDrag(state),
      onWheel: state => handleGestureWheel(state),
    },
    {
      drag: {
        filterTaps: true,
        threshold: 18,
        rubberband: false,
      },
      wheel: {
        eventOptions: { passive: false },
      },
    }
  );

  useEffect(() => {
    if (toggle) {
      setLang(l => (l === 'fr' ? 'en' : 'fr'));
    }
  }, [toggle]);

  const valuesLangCtxt = useMemo(
    () => ({
      flick,
      setFlick,
      flickValue,
      toggle,
      setToggle,
      lang,
    }),
    [flick, toggle, flickValue, lang]
  );

  return {
    valuesLangCtxt,
    ToggleProvider: LangCtxt.Provider,
    bindGesture,
  };
}

export function useToggleScroll(dir: number = 1) {
  const ctx = useContext(LangCtxt);
  if (!ctx) {
    throw new Error('useToggleScroll must be used within LangCtxt provider');
  }
  const { flick, setFlick, flickValue, toggle, setToggle, lang } = ctx;

  const [toggleAnimation] = useSpring(
    {
      from: { transform: 'rotateX(0deg)' },
      to: async (start, stop) => {
        if (toggle) {
          stop();
          await start({
            transform: `rotateX(${dir * (lang === 'fr' ? 0 : 720)}deg)`,
            config: flipConfig,
          });
        }
        if (flick) {
          await start({
            transform: `rotateX(${dir * (lang === 'fr' ? flickValue : 720 + flickValue)}deg)`,
            config: flipConfig,
          });
          await start({
            transform: `rotateX(${dir * (lang === 'fr' ? 0 : 720)}deg)`,
            config: flipConfig,
          });
        }
      },
      onRest: () => {
        if (flick) {
          setFlick(false);
        }
        if (toggle) {
          setToggle(false);
          setFlick(false);
        }
      },
    },
    [toggle, flick, flickValue, lang, dir]
  );

  return [toggleAnimation, lang] as const;
}
